parameters.new_string:
/**
 * Dispatch a notification payload to all registered adapters and
 * persist a record for each delivery attempt.
 * Checks user preferences before sending to email adapters.
 *
 * Dispatches are serialized through a queue to guarantee delivery
 * ordering even when multiple events are emitted concurrently.
 */
private dispatchNotification(payload: NotificationPayload, userId: string): Promise<void> {
  this.dispatchQueue = this.dispatchQueue.then(() =>
    this.executeDispatch(payload, userId),
  );
  return this.dispatchQueue;
}

/**
 * Execute the actual dispatch to adapters. Called serially via the dispatch queue.
 */
private async executeDispatch(payload: NotificationPayload, userId: string): Promise<void> {
  if (this.adapters.length === 0) {
    // No adapters registered — store as in-app notification
    this.persistNotification(payload, 'in-app', true);
    return;
  }

  for (const adapter of this.adapters) {
    // Check per-channel preferences before dispatching
    if (this.preferencesService && (adapter.channel === 'email' || adapter.channel === 'sms' || adapter.channel === 'webhook')) {
      if (!this.preferencesService.shouldSend(adapter.channel, userId, payload.type)) {
        this.logger.info(
          `Skipping ${adapter.channel} for ${userId}: blocked by preferences (${payload.type})`,
        );
        continue;
      }
    }
    const success = await adapter.send(payload);
    this.persistNotification(payload, adapter.channel, success);
  }
}

