describe('notification ordering', () => {
  it('should preserve delivery order when events are emitted concurrently', async () => {
    // Simulate an adapter with variable latency — the second notification
    // would resolve first without the dispatch queue.
    const deliveryOrder: string[] = [];
    let callCount = 0;

    const slowAdapter: NotificationAdapter = {
      channel: 'email',
      async send(payload: NotificationPayload): Promise<boolean> {
        callCount++;
        // First call (order confirmation) is slow; second (status update) is fast
        const delay = callCount === 1 ? 50 : 5;
        await new Promise((resolve) => setTimeout(resolve, delay));
        deliveryOrder.push(payload.type);
        return true;
      },
    };

    service.registerAdapter(slowAdapter);

    const orderCreatedEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    const statusChangedEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    // Emit both events concurrently — without the dispatch queue,
    // the status update would arrive before the order confirmation.
    const p1 = eventBus.emit(orderCreatedEvent);
    const p2 = eventBus.emit(statusChangedEvent);
    await Promise.all([p1, p2]);

    // Delivery order must match emission order
    expect(deliveryOrder).toEqual(['order:confirmation', 'order:status-update']);

    // Persisted notifications should also be in order
    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(2);
    expect(notifications[0]?.type).toBe('order:confirmation');
    expect(notifications[1]?.type).toBe('order:status-update');
  });
});

